INSERT INTO framework_nodes (id, framework_id, parent_id, name, reference_code, node_type, is_assessable, is_active, sort_order, path, depth, acceptance_criteria, created_at, updated_at) VALUES ('c618cc56-c49f-478f-aa44-2326e2d0c20f', '33f661cb-69a0-4c9e-8c3c-94ab4ce40e17', 'd675c1bc-0875-4029-a1ee-cfe3fa6c9d9d', 'AI Methods Explanation', 'R1.3', 'Requirement', true, true, 3, 'R1/R1.3', 1, '- Explain the behavior of the system and ensure the deployment of reliable technology.
